import { execution } from '@dynatrace-sdk/automation-utils';
import { metricsClient } from '@dynatrace-sdk/client-classic-environment-v2';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  const timeFrameMs = parseInt(input.timeFrameMinutes) * 60 * 1000;
  const now = Date.now();
  const from = now - timeFrameMs;
  const to = now;

  try {
    const response = await metricsClient.queryMetricsData({
      metricSelector: `${input.metricSelector}`,
      from: from,
      to: to,
      resolution: `${input.resolution}s`,
      entityFilter: `type(\"${input.entityId.split('-')[0]}\"),entityId(\"${input.entityId}\")`
    });

    console.log(`Retrieved metrics for ${input.entityId}`);

    return {
      entityId: input.entityId,
      metricSelector: input.metricSelector,
      timeFrameMinutes: input.timeFrameMinutes,
      dataPoints: response.result[0]?.data || [],
      nextPageKey: response.nextPageKey || null
    };
  } catch (error) {
    console.error('Error querying metrics:', error);
    throw new Error(`Failed to query metrics: ${error}`);
  }
}
